export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "逃難的隊伍在崎嶇的山路上蜿蜒前行。夜色依然濃重，只有精靈們手中的發光石照亮著前路。隊伍拉得很長，有的精靈攙扶著老人，有的抱著孩子，還有的背著一些搶救出來的物品。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "空氣中依然能聞到淡淡的煙味，提醒著他們剛剛經歷的災難。偶爾回頭，還能看到遠處天空被火光染紅的一角，那是月光林地燃燒的方向。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "隊伍中不時傳來各種聲音。一個精靈幼童在母親懷中啜泣，小小的聲音在夜色中顯得格外清晰。" },
    { characterId: CharacterId.Elf, character: "精靈幼童", dialogue: "(哭泣著) 媽媽...我的玩具...我的房間...都沒有了..." },
    { characterId: CharacterId.Elf, character: "精靈母親", dialogue: "(輕聲安撫，聲音溫柔但也帶著疲憊) 乖...別哭了...只要我們都還在一起就好。玩具可以再做，房子可以再建..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不遠處，幾個年輕的精靈在低聲交談，語氣中帶著憤怒和不解。" },
    { characterId: CharacterId.Elf, character: "年輕精靈A", dialogue: "到底是誰做的？為什麼要襲擊我們？我們精靈族一向與世無爭..." },
    { characterId: CharacterId.Elf, character: "年輕精靈B", dialogue: "一定是外來者！肯定是那些貪婪的人類或者其他種族！他們嫉妒我們的家園！" },
    { characterId: CharacterId.Elf, character: "年輕精靈C", dialogue: "(語氣遲疑) 可是...我們村裡不是也有人類嗎？就是那兩個今天剛來的..." },
    { characterId: CharacterId.Elf, character: "年輕精靈A", dialogue: "(壓低聲音) 你說什麼？你懷疑是他們？" },
    { characterId: CharacterId.Elf, character: "年輕精靈C", dialogue: "我不是這個意思...只是覺得很巧合...他們剛來，村子就著火了..." },
    { characterId: CharacterId.Elf, character: "年輕精靈B", dialogue: "(思考著) 這倒也是...不過我看艾拉如長老對他們很友善，應該不會有問題吧..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰走在人群中，隱約聽到了這些對話。他的心情變得更加沉重。雖然他知道自己和恵美是無辜的，但在這種情況下，作為外來者確實很容易成為懷疑對象。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他下意識地握緊了恵美的手，加快了腳步，盡量遠離那些竊竊私語的精靈。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "又走了一段時間，隊伍終於在一片較為平坦的空地上停了下來。艾拉如舉起手中的發光石，示意大家休息。" },
    { characterId: CharacterId.Ailaru, character: "艾拉如", dialogue: "(聲音雖然疲憊但依然沉穩) 大家休息十五分鐘。喝點水，檢查一下有沒有人受傷。我們已經走了快一個小時，離銀月湖還有一段距離。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "精靈們紛紛坐下，有的靠著樹幹，有的乾脆躺在草地上。空氣中充滿了疲憊的喘息聲。李杰和恵美也找了一塊相對乾燥的石頭坐下。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰從口袋裡掏出在小屋裡拿的水壺，遞給恵美。恵美接過喝了幾口，臉色在發光石的照映下顯得蒼白但平靜。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(看著清水，忍不住問) 清水，妳不覺得很奇怪嗎？到底是誰襲擊了村莊？為什麼要這麼做？" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(輕輕搖頭，語氣平淡) 我也不知道...不過...其實我也不是特別在意這個..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(有些驚訝) 不在意？可是村莊都被燒了..." },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(眼中閃爍著光芒，語氣帶著一絲興奮) 我知道這聽起來很奇怪...但是我有一種感覺...我們去銀月湖，說不定能知道更多關於回去的方法。艾拉如先生說那裡是神聖的地方，對吧？也許...也許那裡會有答案。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰看著恵美臉上的期待，心中既感到欣慰又覺得不可思議。在這種混亂的情況下，她居然還能保持這樣樂觀的態度。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(露出一個苦笑) 妳還真是樂觀啊。我倒是沒那麼有信心...說實話，我現在更擔心的是其他人。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(疑惑地看著他) 其他人？" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "就是那些和我們一起下車的人。那四個大學生，你還記得嗎？還有那個看起來很有擔當的中年大叔...還有那個戴眼鏡的男生..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰的聲音越來越低。眼鏡男的破碎眼鏡和那灘血跡又在腦海中浮現。他不知道其他人現在在哪裡，是否安全，是否還活著。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "我們在森林裡發現了眼鏡男的眼鏡...他很可能已經...至於其他人，大叔選擇去探索另一個方向，那四個學生也不知道做了什麼選擇..." },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(輕聲安慰，語氣篤定) 李杰先生不用太擔心。我覺得...我覺得他們應該沒事的。我有這樣的感覺。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(苦笑) 感覺嗎...希望妳的感覺是對的。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十五分鐘很快過去。艾拉如再次站起身，示意大家繼續前進。精靈們陸續起身，調整好姿勢，重新踏上了前往銀月湖的路。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就這樣，隊伍走走停停。每隔一個小時左右就會停下來休息十五分鐘，然後繼續前進。山路越來越崎嶇，有時需要攀爬一些岩石，有時需要穿過密集的樹林。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰和恵美都已經疲憊不堪。李杰的腿開始發軟，每一步都像是在與地心引力抗爭。恵美更是幾次差點跌倒，都被李杰及時扶住。但兩人都咬牙堅持著，因為他們知道，停下來就意味著被拋棄。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "天空依然是那片永恆的夜色，紫色的雙月高懸，彷彿在冷漠地俯視著這些逃難的生靈。時間變得模糊不清，只有一次又一次的前進和休息，讓他們知道時間還在流逝。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "終於，在又一次爬上山坡後，前方的精靈們爆發出一陣歡呼。艾拉如舉起發光石，指向前方。" },
    { characterId: CharacterId.Ailaru, character: "艾拉如", dialogue: "(聲音中帶著如釋重負的喜悅) 到了！那就是銀月湖！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰抬起頭，順著艾拉如的手勢看去。眼前的景象讓他疲憊的心靈瞬間得到了撫慰。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "銀月湖靜靜地躺在山谷之中，如同一面巨大的鏡子，完美地倒映著天空中的雙月。湖水呈現出一種夢幻般的銀藍色，在月光的照耀下閃爍著柔和的光芒，彷彿整個湖面都鑲嵌著無數顆細小的星辰。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "湖泊周圍是一片開闊的草地，青草在微風中輕輕擺動，散發著清新的氣息。草地的邊緣是茂密的森林，樹木高大筆直，在月光下投下深邃的影子。但與迷霧之森不同，這裡的森林沒有濃霧籠罩，顯得清爽而寧靜。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最令人驚嘆的是，湖面上漂浮著許多會發光的花朵，像是睡蓮，卻散發著淡淡的銀色光芒。它們在湖面上輕輕搖曳，為整個湖泊增添了一絲神秘而聖潔的氣息。空氣中飄散著一種淡淡的花香，清新而舒緩，讓人疲憊的身心瞬間得到放鬆。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "整個銀月湖散發著一種超脫塵世的美，彷彿是被世界遺忘的淨土。在這片永恆的夜色下，它顯得如此平靜、如此純潔，與他們剛剛逃離的火海形成了強烈的對比。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(呆呆地站在原地，喃喃自語) 好美...真的...好美..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從未見過如此美麗而寧靜的地方。在經歷了連日來的驚恐、疲憊、絕望之後，眼前的景象如同奇蹟一般，讓他幾乎忘記了所有的煩惱。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(臉上綻放出燦爛的笑容，聲音裡充滿了喜悅) 終於到了...終於到銀月湖了..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(轉頭看著她，也露出了笑容) 是啊...我們終於到了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "精靈們陸續走下山坡，朝著湖邊走去。艾拉如和幾位看起來地位較高的精靈聚在一起，開始討論安置的問題。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰注意到，湖邊確實有幾座小屋，建築風格與他們在森林裡見過的獵戶小屋相似，但數量並不多，大概只有五六座。對於上百名逃難的精靈來說，這顯然遠遠不夠。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "艾拉如和其他精靈領袖商量了一會兒，然後開始安排。他們優先將老人和孩子安置進小屋，年輕的精靈們則開始在湖邊搭建臨時的帳篷。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "艾拉如走向李杰和恵美，臉上帶著歉意。" },
    { characterId: CharacterId.Ailaru, character: "艾拉如", dialogue: "(有些抱歉地說) 李杰、清水，很抱歉。小屋的數量有限，我們必須先照顧老人和孩子。我這裡有一些簡單的露營裝備，你們可以在湖邊找個地方搭建帳篷休息。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他遞過來兩個布包，裡面有簡單的帆布帳篷、幾條毯子和一些乾糧。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(接過布包，搖搖頭) 沒關係，我們理解。老人和孩子確實更需要房子。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(也點點頭) 謝謝艾拉如先生。" },
    { characterId: CharacterId.Ailaru, character: "艾拉如", dialogue: "(欣慰地點頭) 你們都是善良的人。如果有任何需要，隨時來找我。我會在那邊最大的那座小屋裡。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "艾拉如說完便轉身離開，繼續忙著安置其他精靈。李杰和恵美提著布包，沿著湖邊走著，尋找一個合適的地方搭建帳篷。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "湖邊的草地柔軟而平坦，偶爾能看到一些精靈家庭也在搭建帳篷。孩子們的哭聲已經少了很多，被這片美麗的景色安撫了。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(指著前方一處靠近湖邊但又有幾棵樹遮擋的地方) 那裡怎麼樣？有樹可以擋風，離湖也近，取水方便。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(看了看，點點頭) 嗯，那裡很好。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩人走到那個地方，開始搭建帳篷。雖然都沒有露營的經驗，但在互相配合下，還是勉強把帆布帳篷撐了起來。帳篷很簡陋，但至少能遮風擋雨。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "搭好帳篷後，兩人都累得癱坐在草地上。李杰看著眼前平靜的湖面，聽著輕柔的水聲，感覺身心都得到了前所未有的放鬆。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "銀月湖的月光灑在他們身上，溫柔而寧靜。在這片神聖的土地上，至少今晚，他們是安全的。" },
];
